-- =============================================
-- LEARN GREEK — Part 2: Alphabet Lessons (24)
-- =============================================
-- Run AFTER 01-greek-tables.sql
-- Lesson IDs 1–24 are reserved for alphabet
-- =============================================

-- LETTER 1: ALPHA
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  1, 1, 'alphabet', 'Alpha (Α α)', 'The first letter — Beginning & Eternity',
  '{"letter":"Α","letterLower":"α","name":"Alpha","transliteration":"a","numeric_value":1,"pronunciation":"ah, as in father","pictograph":"From Phoenician Aleph (ox head 𐤀) — represents strength, leadership, and new beginnings","fun_fact":"Jesus declares I am the Alpha and the Omega in Revelation 1:8 and 22:13. By using the first letter of the Greek alphabet He claims to be the source and origin of all things.","practice":[{"type":"identify","question":"What is the name of this Greek letter: Α?","answer":"Alpha"},{"type":"choice","question":"What is the numeric value of Alpha?","options":["1","2","5","10"],"answer":0},{"type":"choice","question":"In Revelation, Jesus calls Himself the Alpha and the ___.","options":["Omega","Beta","Sigma","Zeta"],"answer":0}]}',
  '[{"ref":"Revelation 1:8","text":"I am Alpha and Omega, the beginning and the ending, saith the Lord","note":"Jesus uses the first Greek letter to declare He is the eternal origin of all creation"},{"ref":"Revelation 22:13","text":"I am Alpha and Omega, the beginning and the end, the first and the last","note":"The final self-declaration of Christ — He encompasses all of reality from Α to Ω"}]'
);

-- LETTER 2: BETA
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  2, 2, 'alphabet', 'Beta (Β β)', 'The second letter — House & Dwelling',
  '{"letter":"Β","letterLower":"β","name":"Beta","transliteration":"b","numeric_value":2,"pronunciation":"b, as in boy","pictograph":"From Phoenician Beth (house 𐤁) — represents dwelling, family, and the household of God","fun_fact":"Bethlehem (Βηθλεέμ) means house of bread — Beth plus lehem. The eternal Word of Life was born in the House of Bread. Our word alphabet itself comes from Alpha + Beta!","practice":[{"type":"identify","question":"What is the name of this Greek letter: Β?","answer":"Beta"},{"type":"choice","question":"The word alphabet comes from which two letters?","options":["Alpha + Beta","Beta + Gamma","Alpha + Gamma","Gamma + Delta"],"answer":0},{"type":"choice","question":"Bethlehem comes from Beth (house) and lehem (bread). What does it mean?","options":["House of bread","House of God","House of peace","House of David"],"answer":0}]}',
  '[{"ref":"Matthew 2:1","text":"Now when Jesus was born in Bethlehem of Judaea in the days of Herod the king","note":"Bethlehem — house of bread. The Bread of Life was born in the house whose very name proclaimed Him"},{"ref":"John 6:35","text":"I am the bread of life: he that cometh to me shall never hunger","note":"Jesus, born in the house of bread, declares Himself to be the living bread come down from heaven"}]'
);

-- LETTER 3: GAMMA
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  3, 3, 'alphabet', 'Gamma (Γ γ)', 'The third letter — Scripture & Knowledge',
  '{"letter":"Γ","letterLower":"γ","name":"Gamma","transliteration":"g","numeric_value":3,"pronunciation":"g as in go; sounds like ng before κ, γ, ξ, χ (e.g. ἄγγελος = angelos)","pictograph":"From Phoenician Gimel (camel 𐤂) — represents journeying and carrying burdens","fun_fact":"γραφή (graphē) means Scripture or writing. All γραφή is given by inspiration of God (2 Tim 3:16). Our words graphic, geography, and autograph all come from this Greek root!","practice":[{"type":"identify","question":"What is the name of this Greek letter: Γ?","answer":"Gamma"},{"type":"choice","question":"What does γραφή (graphē) mean?","options":["Prayer","Scripture / writing","Church","Faith"],"answer":1},{"type":"choice","question":"Before which letters does Gamma produce an ng sound?","options":["κ, γ, ξ, χ","π, τ, δ, β","ρ, λ, μ, ν","α, ε, ι, ο"],"answer":0}]}',
  '[{"ref":"2 Timothy 3:16","text":"All scripture is given by inspiration of God, and is profitable for doctrine, for reproof, for correction","note":"The word scripture here is γραφή — every NT book is a divinely inspired γραφή"},{"ref":"John 5:39","text":"Search the scriptures; for in them ye think ye have eternal life: and they are they which testify of me","note":"Jesus commands us to search the γραφαί (scriptures). They all point to Him"}]'
);

-- LETTER 4: DELTA
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  4, 4, 'alphabet', 'Delta (Δ δ)', 'The fourth letter — Power & Doorways',
  '{"letter":"Δ","letterLower":"δ","name":"Delta","transliteration":"d","numeric_value":4,"pronunciation":"d, as in dog","pictograph":"From Phoenician Daleth (door 𐤃) — represents a doorway, a threshold, a new path opening","fun_fact":"δύναμις (dynamis) means power and is the root of our word dynamite. Paul declared the gospel is the δύναμις of God unto salvation (Rom 1:16). The same power that raised Christ from the dead is available to every believer!","practice":[{"type":"identify","question":"What is the name of this Greek letter: Δ?","answer":"Delta"},{"type":"choice","question":"What does δύναμις (dynamis) mean — and what English word comes from it?","options":["Power — dynamite","Faith — dynamic","Love — dynamism","Grace — dynamo"],"answer":0},{"type":"choice","question":"What is the numeric value of Delta?","options":["3","4","5","6"],"answer":1}]}',
  '[{"ref":"Romans 1:16","text":"For I am not ashamed of the gospel of Christ: for it is the power of God unto salvation to every one that believeth","note":"Power here is δύναμις — the same root as dynamite. The gospel carries explosive divine power"},{"ref":"Acts 1:8","text":"But ye shall receive power, after that the Holy Ghost is come upon you: and ye shall be witnesses unto me","note":"Power again is δύναμις — the Holy Spirit brings transforming divine power (dynamis) into our lives"}]'
);

-- LETTER 5: EPSILON
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  5, 5, 'alphabet', 'Epsilon (Ε ε)', 'The fifth letter — The short E, Good News',
  '{"letter":"Ε","letterLower":"ε","name":"Epsilon","transliteration":"e","numeric_value":5,"pronunciation":"SHORT e, as in met (never the long ee sound — that is Eta η)","pictograph":"From Phoenician He (window 𐤄) — represents breath, light coming through, revelation","fun_fact":"εὐαγγέλιον (euangelion) = gospel / good news, and it starts with Epsilon! Eu means good, angelion means message. The word evangelist, evangelical, and evangelism all come from this Epsilon word.","practice":[{"type":"identify","question":"What is the name of this Greek letter: Ε?","answer":"Epsilon"},{"type":"choice","question":"εὐαγγέλιον (euangelion) means good news / gospel. What does eu mean?","options":["Good","God","True","New"],"answer":0},{"type":"choice","question":"Epsilon is always a SHORT sound. Which letter is the LONG e in Greek?","options":["Alpha","Eta","Iota","Omega"],"answer":1}]}',
  '[{"ref":"Mark 1:15","text":"The time is fulfilled, and the kingdom of God is at hand: repent ye, and believe the gospel","note":"Gospel here is εὐαγγέλιον — the good message that begins with Epsilon"},{"ref":"1 Corinthians 15:1","text":"Moreover, brethren, I declare unto you the gospel which I preached unto you, which also ye have received","note":"Paul stakes everything on the εὐαγγέλιον — the good news of Christ crucified and risen"}]'
);

-- LETTER 6: ZETA
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  6, 6, 'alphabet', 'Zeta (Ζ ζ)', 'The sixth letter — Life & Vitality',
  '{"letter":"Ζ","letterLower":"ζ","name":"Zeta","transliteration":"z","numeric_value":7,"pronunciation":"z as in zone (in Koine/NT Greek). Classical Greek said dz as in adze","pictograph":"From Phoenician Zayin (weapon 𐤆) — represents sharpness, the cutting edge of truth","fun_fact":"ζωή (zōē) means life — specifically eternal and spiritual life. Jesus said I am the way, the truth, and the ζωή (John 14:6). There are two words for life in Greek: bios (biological/physical life) and zōē (spiritual, God-quality life). Jesus offers zōē!","practice":[{"type":"identify","question":"What is the name of this Greek letter: Ζ?","answer":"Zeta"},{"type":"choice","question":"What does ζωή (zōē) mean?","options":["Death","Life (eternal/spiritual)","Light","Love"],"answer":1},{"type":"choice","question":"Greek has two words for life. Zōē means spiritual life. What does bios mean?","options":["Eternal life","Physical / biological life","Abundant life","New life"],"answer":1}]}',
  '[{"ref":"John 14:6","text":"I am the way, the truth, and the life: no man cometh unto the Father, but by me","note":"Life here is ζωή — not mere biological existence but the eternal, divine life that only Christ can give"},{"ref":"John 10:10","text":"I am come that they might have life, and that they might have it more abundantly","note":"Again ζωή — Jesus came to give us God-quality life in overflowing abundance"}]'
);

-- LETTER 7: ETA
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  7, 7, 'alphabet', 'Eta (Η η)', 'The seventh letter — The long E, New Beginnings',
  '{"letter":"Η","letterLower":"η","name":"Eta","transliteration":"ē","numeric_value":8,"pronunciation":"LONG ay as in day or hey — hold the sound longer than Epsilon","pictograph":"From Phoenician Heth (fence / enclosed courtyard 𐤇) — represents a protected, sacred space","fun_fact":"Eta equals 8 in Greek numerals. Eight is the number of new beginnings in Scripture: Noah saved 8 souls through the flood; circumcision was performed on the 8th day. After the 7th day (Sabbath rest) comes the 8th — new creation!","practice":[{"type":"identify","question":"What is the name of this Greek letter: Η?","answer":"Eta"},{"type":"choice","question":"What is the numeric value of Eta — also significant as the number of new beginnings?","options":["6","7","8","9"],"answer":2},{"type":"choice","question":"Eta is the LONG e sound. Epsilon is the SHORT e. How should you pronounce Eta?","options":["ee (like feet)","ay (like day, held longer)","ah (like father)","oh (like home)"],"answer":1}]}',
  '[{"ref":"1 Peter 3:20","text":"Which sometime were disobedient, when once the longsuffering of God waited in the days of Noah, while the ark was a preparing, wherein few, that is, eight souls were saved by water","note":"Eight (Eta = 8) souls saved — a picture of resurrection and new beginning through the waters of baptism"},{"ref":"2 Corinthians 5:17","text":"Therefore if any man be in Christ, he is a new creature: old things are passed away; behold, all things are become new","note":"New creation — the eighth-day reality. In Christ we step into eternal newness"}]'
);

-- LETTER 8: THETA
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  8, 8, 'alphabet', 'Theta (Θ θ)', 'The eighth letter — The God Letter',
  '{"letter":"Θ","letterLower":"θ","name":"Theta","transliteration":"th","numeric_value":9,"pronunciation":"th as in think or theology (never the voiced th of the word the)","pictograph":"From Phoenician Teth (wheel or coiled serpent 𐤈) — represents completeness and turning","fun_fact":"θεός (theos) means God and appears 1,317 times in the NT. It is the signature Theta word. Ancient NT scribes abbreviated sacred names (nomina sacra) — θεός was written as ΘΣ with a line over it. When you see Θ, think of God.","practice":[{"type":"identify","question":"What is the name of this Greek letter: Θ?","answer":"Theta"},{"type":"choice","question":"θεός (theos) means God. Which English word-family comes directly from theos?","options":["Theology, theocracy, theist","Theory, theorem, thesis","Thermal, thermometer","Theater, theme, thesis"],"answer":0},{"type":"choice","question":"How should you pronounce Theta (Θ)?","options":["t as in top","th as in the","th as in think","d as in dog"],"answer":2}]}',
  '[{"ref":"John 1:1","text":"In the beginning was the Word, and the Word was with God, and the Word was God","note":"θεός appears twice in this verse — the most profound declaration about divine nature in all of Scripture"},{"ref":"1 John 4:8","text":"He that loveth not knoweth not God; for God is love","note":"θεός ἀγάπη ἐστίν — God IS love. The nature of God expressed in four Greek words"}]'
);

-- LETTER 9: IOTA
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  9, 9, 'alphabet', 'Iota (Ι ι)', 'The ninth letter — The smallest, yet eternal',
  '{"letter":"Ι","letterLower":"ι","name":"Iota","transliteration":"i","numeric_value":10,"pronunciation":"ee as in feet (always the long ee sound)","pictograph":"From Phoenician Yod (hand 𐤉) — represents work, deed, and divine action. Yod is also the first letter of God''s name YHWH!","fun_fact":"Jesus said not one jot (ἰῶτα) shall pass from the law until all is fulfilled (Matt 5:18 KJV). Iota is the SMALLEST Greek letter — just a tiny stroke — yet Jesus said every single stroke of Scripture matters eternally. Not one iota will be forgotten!","practice":[{"type":"identify","question":"What is the name of this Greek letter: Ι?","answer":"Iota"},{"type":"choice","question":"Jesus said not one ___ (the smallest Greek letter) shall pass from the law (Matt 5:18).","options":["Omega","Iota (jot)","Sigma","Tau"],"answer":1},{"type":"choice","question":"What is the numeric value of Iota?","options":["5","8","10","12"],"answer":2}]}',
  '[{"ref":"Matthew 5:18","text":"For verily I say unto you, Till heaven and earth pass, one jot or one tittle shall in no wise pass from the law, till all be fulfilled","note":"Jot is ἰῶτα — iota. Jesus guarantees the permanence of every stroke of Scripture. Not one iota will fail"},{"ref":"Luke 16:17","text":"And it is easier for heaven and earth to pass, than one tittle of the law to fail","note":"The tiniest mark in Scripture is upheld by the eternal word of Christ — not one iota of God''s promise fails"}]'
);

-- LETTER 10: KAPPA
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  10, 10, 'alphabet', 'Kappa (Κ κ)', 'The tenth letter — Lord & Authority',
  '{"letter":"Κ","letterLower":"κ","name":"Kappa","transliteration":"k","numeric_value":20,"pronunciation":"k as in kite (never silent, always crisp)","pictograph":"From Phoenician Kaph (open palm of hand 𐤊) — represents receiving, grasping, and extending grace","fun_fact":"κύριος (kyrios) means Lord and is used 748 times in the NT. The earliest Christian confession was κύριος Ἰησοῦς — Jesus is Lord (Rom 10:9). Every knee will bow and every tongue confess that Jesus Christ is κύριος (Phil 2:11)!","practice":[{"type":"identify","question":"What is the name of this Greek letter: Κ?","answer":"Kappa"},{"type":"choice","question":"What does κύριος (kyrios) mean?","options":["Savior","Lord","King","Master"],"answer":1},{"type":"choice","question":"What is the earliest recorded Christian confession involving a Kappa word?","options":["Jesus saves","Jesus is Lord (κύριος Ἰησοῦς)","Jesus is King","Jesus is God"],"answer":1}]}',
  '[{"ref":"Romans 10:9","text":"That if thou shalt confess with thy mouth the Lord Jesus, and shalt believe in thine heart that God hath raised him from the dead, thou shalt be saved","note":"Lord here is κύριος — the confession of Kappa. This declaration of Christ''s lordship brings salvation"},{"ref":"Philippians 2:11","text":"And that every tongue should confess that Jesus Christ is Lord, to the glory of God the Father","note":"κύριος again — ultimately every created being will acknowledge the Lordship of Jesus Christ"}]'
);

-- LETTER 11: LAMBDA
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  11, 11, 'alphabet', 'Lambda (Λ λ)', 'The eleventh letter — The Word & Reason',
  '{"letter":"Λ","letterLower":"λ","name":"Lambda","transliteration":"l","numeric_value":30,"pronunciation":"l as in love (clear, liquid sound)","pictograph":"From Phoenician Lamed (ox goad 𐤋) — represents direction, teaching, and guiding toward a goal","fun_fact":"λόγος (logos) means Word, Reason, or Divine Expression. John opens his Gospel: In the beginning was the λόγος. Greek philosophers saw logos as the ordering reason behind the universe. John declares: that Logos is a Person — Jesus Christ — and He became flesh!","practice":[{"type":"identify","question":"What is the name of this Greek letter: Λ?","answer":"Lambda"},{"type":"choice","question":"What does λόγος (logos) mean?","options":["Love","Word / Reason / Divine Expression","Law","Light"],"answer":1},{"type":"choice","question":"John 1:1 says In the beginning was the logos. John 1:14 tells us what happened to the logos. What was it?","options":["It became law","It became flesh","It became light","It became love"],"answer":1}]}',
  '[{"ref":"John 1:1","text":"In the beginning was the Word, and the Word was with God, and the Word was God","note":"Word is λόγος — the eternal divine reason and expression. Lambda launches the most profound verse about Christ in all of Scripture"},{"ref":"John 1:14","text":"And the Word was made flesh, and dwelt among us, and we beheld his glory","note":"The λόγος became σάρξ (flesh) — the eternal Word took on human nature. Lambda carries the weight of the Incarnation"}]'
);

-- LETTER 12: MU
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  12, 12, 'alphabet', 'Mu (Μ μ)', 'The twelfth letter — Discipleship & Learning',
  '{"letter":"Μ","letterLower":"μ","name":"Mu","transliteration":"m","numeric_value":40,"pronunciation":"m as in mother (simple nasal sound)","pictograph":"From Phoenician Mem (water 𐤌) — represents flow, cleansing, and revelation flowing like water","fun_fact":"μαθητής (mathētēs) means disciple or learner and appears 261 times in the Gospels and Acts. Jesus calls us all to be μαθηταί — not just believers but active learners and followers. The word mathematics also comes from the same root (máthēma = that which is learned)!","practice":[{"type":"identify","question":"What is the name of this Greek letter: Μ?","answer":"Mu"},{"type":"choice","question":"What does μαθητής (mathētēs) mean?","options":["Apostle","Disciple / learner","Elder","Prophet"],"answer":1},{"type":"choice","question":"The Great Commission says to make disciples of all nations. The word disciple is μαθητής. What did Jesus command His disciples to do?","options":["Build temples","Make more disciples (μαθηταί)","Write Scripture","Perform miracles only"],"answer":1}]}',
  '[{"ref":"Matthew 28:19","text":"Go ye therefore, and teach all nations, baptizing them in the name of the Father, and of the Son, and of the Holy Ghost","note":"Teach all nations is literally make disciples (μαθητεύσατε) — Mu''s great commission word. The church''s core calling"},{"ref":"John 8:31","text":"If ye continue in my word, then are ye my disciples indeed","note":"Disciples (μαθηταί) are defined by continuing in Christ''s word — learning, abiding, and obeying"}]'
);

-- LETTER 13: NU
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  13, 13, 'alphabet', 'Nu (Ν ν)', 'The thirteenth letter — The hidden N',
  '{"letter":"Ν","letterLower":"ν","name":"Nu","transliteration":"n","numeric_value":50,"pronunciation":"n as in now — CAUTION: lowercase ν looks like English v but is always the n sound!","pictograph":"From Phoenician Nun (fish 𐤍) — represents life, movement, and abundance. Early Christians used the fish as their secret symbol!","fun_fact":"The Phoenician letter Nun means fish. The early church adopted ΙΧΘΥΣ (ichthys, fish) as their secret symbol: Ἰησοῦς Χριστός Θεοῦ Υἱὸς Σωτήρ — Jesus Christ, Son of God, Savior. Every letter of that acronym is in this alphabet! Also: νόμος (nomos) = law appears 194 times in the NT.","practice":[{"type":"identify","question":"What is the name of this Greek letter: Ν?","answer":"Nu"},{"type":"choice","question":"WARNING: Lowercase ν looks like English v, but what sound does it make?","options":["v as in vine","n as in now","u as in up","m as in mom"],"answer":1},{"type":"choice","question":"The Phoenician ancestor of Nu meant fish. What did early Christians use the fish symbol (ΙΧΘΥΣ) for?","options":["A secret acronym for Jesus Christ Son of God Savior","A symbol for baptism only","A sign of the Sabbath","A mark for church buildings"],"answer":0}]}',
  '[{"ref":"Matthew 4:19","text":"And he saith unto them, Follow me, and I will make you fishers of men","note":"Jesus calls fishermen using imagery tied to Nu''s Phoenician ancestor (Nun = fish). The disciples become fishers of souls"},{"ref":"John 21:11","text":"Simon Peter went up, and drew the net to land full of great fishes, an hundred and fifty and three","note":"The miraculous catch of fish — a sign of the gospel harvest. Nu''s fish heritage points to the abundance of souls brought into the kingdom"}]'
);

-- LETTER 14: XI
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  14, 14, 'alphabet', 'Xi (Ξ ξ)', 'The fourteenth letter — The Cross & the Wood',
  '{"letter":"Ξ","letterLower":"ξ","name":"Xi","transliteration":"x","numeric_value":60,"pronunciation":"ks blended together as in fox or tax (one sound, not two separate letters)","pictograph":"From Phoenician Samekh (support / pillar 𐤎) — represents sustaining, upholding, the support that holds everything","fun_fact":"ξύλον (xylon) means wood or tree and is used in Acts 5:30 for the cross: whom ye slew and hanged on a tree (ξύλον). Paul quotes Deuteronomy in Galatians 3:13: Cursed is every one that hangeth on a tree (ξύλον). A common piece of wood became the instrument of our eternal salvation!","practice":[{"type":"identify","question":"What is the name of this Greek letter: Ξ?","answer":"Xi"},{"type":"choice","question":"What does ξύλον (xylon) mean — used for the cross in Acts 5:30?","options":["Stone","Wood / tree","Iron","Earth"],"answer":1},{"type":"choice","question":"How do you pronounce Xi?","options":["zy as in azure","z alone","ks blended as in fox","ex as in exit"],"answer":2}]}',
  '[{"ref":"Acts 5:30","text":"The God of our fathers raised up Jesus, whom ye slew and hanged on a tree","note":"Tree here is ξύλον — the Xi word. The cross was a piece of wood (xylon), yet on it hung the salvation of the world"},{"ref":"Galatians 3:13","text":"Christ hath redeemed us from the curse of the law, being made a curse for us: for it is written, Cursed is every one that hangeth on a tree","note":"Tree again is ξύλον. Christ took the curse (hanging on ξύλον) to break our curse — the greatest exchange in history"}]'
);

-- LETTER 15: OMICRON
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  15, 15, 'alphabet', 'Omicron (Ο ο)', 'The fifteenth letter — The small O',
  '{"letter":"Ο","letterLower":"ο","name":"Omicron","transliteration":"o","numeric_value":70,"pronunciation":"SHORT o as in not or top (never the long oh sound — that is Omega ω)","pictograph":"From Phoenician Ayin (eye 𐤏) — represents seeing, insight, and perception","fun_fact":"Omicron literally means small O in Greek (ὂ μικρόν). It contrasts with Omega which means great O (ὦ μέγα). Both were originally one sound but Greek later distinguished short and long. οὐρανός (ouranos) means heaven and appears 284 times in the NT — every time someone prays Our Father in heaven, they use an Omicron word!","practice":[{"type":"identify","question":"What is the name of this Greek letter: Ο?","answer":"Omicron"},{"type":"choice","question":"Omicron (Ο) is always a SHORT o. Which letter is the LONG o in Greek?","options":["Theta","Upsilon","Omega","Nu"],"answer":2},{"type":"choice","question":"What does οὐρανός (ouranos) mean?","options":["Earth","Heaven","Sea","Light"],"answer":1}]}',
  '[{"ref":"Matthew 6:9","text":"Our Father which art in heaven, Hallowed be thy name","note":"Heaven here is οὐρανοῖς — an Omicron word. Every time we pray the Lord''s Prayer we begin with this letter"},{"ref":"Revelation 3:12","text":"Him that overcometh will I make a pillar in the temple of my God, and he shall go no more out: and I will write upon him the name of my God, and the name of the city of my God, which is new Jerusalem, which cometh down out of heaven","note":"Heaven (οὐρανοῦ) — the destination of the overcomers. Omicron opens the most important preposition in this promise"}]'
);

-- LETTER 16: PI
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  16, 16, 'alphabet', 'Pi (Π π)', 'The sixteenth letter — Faith & Spirit',
  '{"letter":"Π","letterLower":"π","name":"Pi","transliteration":"p","numeric_value":80,"pronunciation":"p as in pen (clear, never aspirated with breath)","pictograph":"From Phoenician Pe (mouth 𐤐) — represents speech, expression, and the spoken word","fun_fact":"πίστις (pistis) means faith and appears 244 times in the NT. The just shall live by πίστις (Rom 1:17) — Paul''s core thesis from Habakkuk. Also: πνεῦμα (pneuma) = Spirit and πατήρ (patēr) = Father. The Father, the Spirit, and our faith — all begin with Pi!","practice":[{"type":"identify","question":"What is the name of this Greek letter: Π?","answer":"Pi"},{"type":"choice","question":"What does πίστις (pistis) mean?","options":["Power","Peace","Faith / trust","Praise"],"answer":2},{"type":"choice","question":"Which three important NT words all begin with Pi (π)?","options":["Faith, Spirit, Father (πίστις, πνεῦμα, πατήρ)","Peace, Prayer, Praise","Prophet, Priest, Prince","Power, People, Place"],"answer":0}]}',
  '[{"ref":"Romans 1:17","text":"For therein is the righteousness of God revealed from faith to faith: as it is written, The just shall live by faith","note":"Faith is πίστις — the Pi word that Paul builds his entire letter to Rome upon. Everything flows from πίστις"},{"ref":"Hebrews 11:1","text":"Now faith is the substance of things hoped for, the evidence of things not seen","note":"The most famous definition of πίστις in all of Scripture. Faith is not blind — it is the evidence, the title deed of things not yet visible"}]'
);

-- LETTER 17: RHO
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  17, 17, 'alphabet', 'Rho (Ρ ρ)', 'The seventeenth letter — The P that sounds like R',
  '{"letter":"Ρ","letterLower":"ρ","name":"Rho","transliteration":"r","numeric_value":100,"pronunciation":"r, ideally rolled or trilled like Spanish r (English r also acceptable)","pictograph":"From Phoenician Resh (head 𐤓) — represents headship, the top, authority, and the beginning of something","fun_fact":"VISUAL TRAP: Uppercase Ρ looks exactly like English P — but it is always the R sound! The famous Chi-Rho symbol ☧ uses this letter: X is Chi (Ch) and P is Rho (R) together = ChR = Christos (Christ). Emperor Constantine saw this symbol before his famous victory!","practice":[{"type":"identify","question":"What is the name of this Greek letter: Ρ?","answer":"Rho"},{"type":"choice","question":"WARNING: Rho (Ρ) looks like which English letter but sounds completely different?","options":["B","D","P","Q"],"answer":2},{"type":"choice","question":"The Chi-Rho symbol (☧) is made of Chi (Χ) and Rho (Ρ). What word do these two letters begin?","options":["Christos (Christ)","Christiana (Christian)","Chronos (time)","Charis (grace)"],"answer":0}]}',
  '[{"ref":"John 10:11","text":"I am the good shepherd: the good shepherd giveth his life for the sheep","note":"Shepherd in Greek is ποιμήν but the Rho-derived word ῥῆμα (spoken word) flows from this — Christ speaks as the shepherd-king whose word carries authority"},{"ref":"Revelation 7:17","text":"For the Lamb which is in the midst of the throne shall feed them, and shall lead them unto living fountains of waters","note":"The Lamb as shepherd-king (ποιμανεῖ) — the Chi-Rho (Christos) who leads His flock to eternal springs"}]'
);

-- LETTER 18: SIGMA
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  18, 18, 'alphabet', 'Sigma (Σ σ ς)', 'The eighteenth letter — The two-faced letter',
  '{"letter":"Σ","letterLower":"σ / ς","name":"Sigma","transliteration":"s","numeric_value":200,"pronunciation":"s as in sun (never z)","pictograph":"From Phoenician Shin (teeth 𐤔) — represents sharpness, the pressing or hissing sound","fun_fact":"Sigma is the only Greek letter with TWO lowercase forms: σ is used at the beginning or middle of a word, and ς (final sigma) is used ONLY at the end of a word. Χριστός (Christos) ends with ς! Watch for this in your NT Greek — it helps you identify word boundaries.","practice":[{"type":"identify","question":"What is the name of this Greek letter: Σ?","answer":"Sigma"},{"type":"choice","question":"Sigma has two lowercase forms. Which form appears at the END of a word?","options":["σ (sigma)","ς (final sigma)","ξ (xi)","ζ (zeta)"],"answer":1},{"type":"choice","question":"The word Χριστός (Christos = Christ) ends in which letter?","options":["Sigma (σ)","Final Sigma (ς)","Omicron (ο)","Upsilon (υ)"],"answer":1}]}',
  '[{"ref":"Matthew 16:16","text":"And Simon Peter answered and said, Thou art the Christ, the Son of the living God","note":"Christ is Χριστός ending in final sigma (ς). Peter''s great confession contains the Sigma letter that marks the end of the word — and the turning point of the Gospels"},{"ref":"Acts 4:12","text":"Neither is there salvation in any other: for there is none other name under heaven given among men, whereby we must be saved","note":"Salvation (σωτηρία) begins with Sigma — the letter whose shape echoes the curve of a protecting arm around God''s people"}]'
);

-- LETTER 19: TAU
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  19, 19, 'alphabet', 'Tau (Τ τ)', 'The nineteenth letter — The cross-shaped letter',
  '{"letter":"Τ","letterLower":"τ","name":"Tau","transliteration":"t","numeric_value":300,"pronunciation":"t as in top (clean, not aspirated)","pictograph":"From Phoenician Tav (mark / cross 𐤕) — in ancient form the Tav was written as an X or + shape. It was the LAST letter of the Hebrew alphabet, used as a seal or mark","fun_fact":"Tau is the last letter of the Hebrew alphabet (Tav). In Ezekiel 9:4, God commanded His angel to put a mark (tav) on the foreheads of the faithful before judgment — and the ancient tav was cross-shaped! Early Christians saw this as a prophecy of the cross. The cross is literally written into the alphabet!","practice":[{"type":"identify","question":"What is the name of this Greek letter: Τ?","answer":"Tau"},{"type":"choice","question":"The ancient Phoenician form of Tau (Tav) was shaped like a cross or X. In Ezekiel 9:4, what was this mark used for?","options":["Marking enemies for destruction","Marking the faithful for protection","Marking the temple boundary","Marking the priest''s forehead"],"answer":1},{"type":"choice","question":"What is the numeric value of Tau?","options":["200","300","400","500"],"answer":1}]}',
  '[{"ref":"Ezekiel 9:4","text":"Go through the midst of the city, through the midst of Jerusalem, and set a mark upon the foreheads of the men that sigh and that cry for all the abominations that be done in the midst thereof","note":"The mark (tav in Hebrew) was cross-shaped in ancient script. God''s protective seal over His people — a foreshadowing of the blood of the cross"},{"ref":"Galatians 6:14","text":"But God forbid that I should glory, save in the cross of our Lord Jesus Christ","note":"Cross is σταυρός — but Paul''s boast is in what the Tau-shaped Tav always pointed to: the instrument of redemption"}]'
);

-- LETTER 20: UPSILON
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  20, 20, 'alphabet', 'Upsilon (Υ υ)', 'The twentieth letter — Son & Sonship',
  '{"letter":"Υ","letterLower":"υ","name":"Upsilon","transliteration":"y / u","numeric_value":400,"pronunciation":"Similar to French u or German ü — round your lips as if to say oo, then say ee. No direct English equivalent","pictograph":"From Phoenician Vav (hook / peg 𐤅) — represents connection, joining, and being fastened to something","fun_fact":"υἱός (huios) means son and is used 382 times in the NT. The central claim of the NT is υἱὸς τοῦ θεοῦ — Son of God. For God so loved the world that He gave His only begotten υἱός (John 3:16). Upsilon carries the weight of the greatest declaration of love ever made.","practice":[{"type":"identify","question":"What is the name of this Greek letter: Υ?","answer":"Upsilon"},{"type":"choice","question":"What does υἱός (huios) mean?","options":["Spirit","Father","Son","King"],"answer":2},{"type":"choice","question":"How many times does υἱός (son) appear in the NT — showing how central sonship is to the gospel?","options":["About 50","About 150","About 382","About 600"],"answer":2}]}',
  '[{"ref":"John 3:16","text":"For God so loved the world, that he gave his only begotten Son, that whosoever believeth in him should not perish, but have everlasting life","note":"Son is υἱόν — the Upsilon word at the heart of the entire gospel. The Father gave His Son (υἱός) so we might become sons"},{"ref":"Matthew 3:17","text":"And lo a voice from heaven, saying, This is my beloved Son, in whom I am well pleased","note":"The Father''s declaration at Jesus'' baptism: υἱός μου ὁ ἀγαπητός — my beloved Son. Upsilon carries the Father''s love in this moment"}]'
);

-- LETTER 21: PHI
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  21, 21, 'alphabet', 'Phi (Φ φ)', 'The twenty-first letter — Light & Revelation',
  '{"letter":"Φ","letterLower":"φ","name":"Phi","transliteration":"ph","numeric_value":500,"pronunciation":"f as in phone (a single f sound — not p-h as two letters)","pictograph":"A uniquely Greek letter, developed from an early variant of Pi. The circle with a line through it may represent a torch or burning flame","fun_fact":"φῶς (phōs) means light — God is φῶς (1 John 1:5). The English word photograph means light-writing (φῶς + γράφω). Φωτισμός (phōtismos) means illumination — the same root is translated as enlightened in Hebrews 6:4. When God''s Word enters, it brings phōs!","practice":[{"type":"identify","question":"What is the name of this Greek letter: Φ?","answer":"Phi"},{"type":"choice","question":"What does φῶς (phōs) mean?","options":["Fire","Light","Truth","Life"],"answer":1},{"type":"choice","question":"The word photograph comes from Greek. Photo means light (φῶς). What does graph mean (γράφω)?","options":["To see","To record / write","To speak","To know"],"answer":1}]}',
  '[{"ref":"John 1:5","text":"And the light shineth in darkness; and the darkness comprehended it not","note":"Light is φῶς — the Phi word. Christ the φῶς enters the darkness of this world and the darkness cannot overcome it"},{"ref":"1 John 1:5","text":"This then is the message which we have heard of him, and declare unto you, that God is light, and in him is no darkness at all","note":"God is φῶς — absolute, perfect light. No shadow, no darkness. Phi carries one of the most profound statements about God''s nature"}]'
);

-- LETTER 22: CHI
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  22, 22, 'alphabet', 'Chi (Χ χ)', 'The twenty-second letter — The Christ letter',
  '{"letter":"Χ","letterLower":"χ","name":"Chi","transliteration":"ch","numeric_value":600,"pronunciation":"ch as in the Scottish loch or German Bach — a guttural sound in the throat, NOT ch as in church","pictograph":"A uniquely Greek letter (though the shape influenced later alphabets). Its X shape has made it historically significant","fun_fact":"Χριστός (Christos) = the Anointed One / Christ begins with Chi. The X in Xmas is NOT removing Christ from Christmas — X is Chi, the first letter of Christ''s title in Greek! Early Christians used ☧ (Chi-Rho, the first two letters of Christos) as their secret symbol. This is the Christ letter.","practice":[{"type":"identify","question":"What is the name of this Greek letter: Χ?","answer":"Chi"},{"type":"choice","question":"The X in Xmas represents Chi (Χ), the first letter of which Greek word?","options":["Χαρά (chara, joy)","Χριστός (Christos, Christ)","Χάρις (charis, grace)","Χρόνος (chronos, time)"],"answer":1},{"type":"choice","question":"How should Chi (Χ) be pronounced?","options":["ch as in church","k as in kite","sh as in shoe","ch as in loch (guttural)"],"answer":3}]}',
  '[{"ref":"Matthew 1:16","text":"And Jacob begat Joseph the husband of Mary, of whom was born Jesus, who is called Christ","note":"Christ is Χριστός — the Chi word. Every time Christ is written in Greek, the Chi letter appears first, secretly displaying the cross-shaped X"},{"ref":"Acts 11:26","text":"And the disciples were called Christians first in Antioch","note":"Christians (Χριστιανοί) begins with Chi. The followers of the Χριστός were named after Him — identified by the Chi-letter from the very beginning"}]'
);

-- LETTER 23: PSI
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  23, 23, 'alphabet', 'Psi (Ψ ψ)', 'The twenty-third letter — Soul & Inner Life',
  '{"letter":"Ψ","letterLower":"ψ","name":"Psi","transliteration":"ps","numeric_value":700,"pronunciation":"ps blended together as in lips or maps (one sound at the START of a word — unusual in English but common in Greek)","pictograph":"A uniquely Greek letter. Its trident shape may represent the soul reaching upward in three aspects: mind, will, and emotion","fun_fact":"ψυχή (psychē) means soul or inner life and appears 103 times in the NT. Our word psychology literally means study of the soul (ψυχή + λόγος). Jesus asked: what is a man profited, if he shall gain the whole world, and lose his own ψυχή? (Matt 16:26). Your soul has eternal value!","practice":[{"type":"identify","question":"What is the name of this Greek letter: Ψ?","answer":"Psi"},{"type":"choice","question":"What does ψυχή (psychē) mean — and what English word comes from it?","options":["Spirit — spiritual","Soul — psychology","Mind — psychic","Life — psychedelic"],"answer":1},{"type":"choice","question":"Jesus asked what profit is it to gain the whole world but lose your ψυχή. What is ψυχή?","options":["Wealth","Reputation","Soul / inner life","Health"],"answer":2}]}',
  '[{"ref":"Matthew 16:26","text":"For what is a man profited, if he shall gain the whole world, and lose his own soul? or what shall a man give in exchange for his soul?","note":"Soul is ψυχή — the Psi word. Jesus places infinite value on the eternal soul that Psi represents"},{"ref":"1 Thessalonians 5:23","text":"And the very God of peace sanctify you wholly; and I pray God your whole spirit and soul and body be preserved blameless","note":"Soul (ψυχή) named alongside spirit (πνεῦμα) and body (σῶμα). The full person — Psi represents the middle dimension of our being"}]'
);

-- LETTER 24: OMEGA
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  24, 24, 'alphabet', 'Omega (Ω ω)', 'The twenty-fourth letter — The End & Eternity',
  '{"letter":"Ω","letterLower":"ω","name":"Omega","transliteration":"ō","numeric_value":800,"pronunciation":"LONG oh as in tone or home — always long, always held. Contrast with Omicron (short o)","pictograph":"Omega developed as an extended form of Omicron — ὦ μέγα means great O. It was added to the alphabet to distinguish the long and short o sounds","fun_fact":"Omega is the LAST letter of the Greek alphabet. Jesus declares I am the Alpha AND the Omega (Rev 22:13) — the first letter and the last letter, the beginning and the end. He encompasses the entire alphabet, which means He encompasses every word, every story, every life. From A to Z is entirely contained within Christ!","practice":[{"type":"identify","question":"What is the name of this Greek letter: Ω?","answer":"Omega"},{"type":"choice","question":"Omega is the LAST Greek letter. Omicron is the short o. Omega is the long o. What does Omega literally mean?","options":["Great O (ὦ μέγα)","Final letter","Holy O","Ending O"],"answer":0},{"type":"choice","question":"Jesus declares I am the Alpha and Omega in Revelation. What does this title mean?","options":["He is the greatest","He is first and last, the beginning and end, encompassing all","He invented the alphabet","He is eternal only in the future"],"answer":1}]}',
  '[{"ref":"Revelation 1:8","text":"I am Alpha and Omega, the beginning and the ending, saith the Lord, which is, and which was, and which is to come, the Almighty","note":"From Α (Alpha) to Ω (Omega) — the first declaration of Christ as the totality of existence. All 24 letters find their meaning in Him"},{"ref":"Revelation 22:13","text":"I am Alpha and Omega, the beginning and the end, the first and the last","note":"The final Omega — the last letter of the last book speaks the last self-declaration of Christ. We end where we began: in Him. Every letter of this alphabet was a step toward knowing the One who IS the Word"}]'
);

-- Reset the sequence so future auto-inserts start after ID 24
SELECT setval('greek_lessons_id_seq', 24);
